from spyne import Application, rpc, ServiceBase, Integer, Float, Unicode, Iterable, Array
from spyne.protocol.soap import Soap11
from spyne.protocol.soap import SoapFault
from spyne.model.primitive import String
from spyne.model.complex import ComplexModel
from spyne.service import ServiceBase
from spyne import Server

class Account(ComplexModel):
    account_number = String
    balance = Float

class FinancialService(ServiceBase):
    accounts = {
        '123456': Account(account_number='123456', balance=1000.0),
        '654321': Account(account_number='654321', balance=500.0),
    }

    @rpc(String, _returns=Float, soap_action='getBalance')
    def getBalance(self, account_number):
        account = self.accounts.get(account_number)
        if account:
            return account.balance
        else:
            raise SoapFault('AccountNotFound', f'Account {account_number} not found.')

    @rpc(String, Float, _returns=String, soap_action='transferFunds')
    def transferFunds(self, from_account, amount):
        if from_account in self.accounts and self.accounts[from_account].balance >= amount:
            self.accounts[from_account].balance -= amount
            return f'Transferred {amount} from {from_account}.'
        else:
            raise SoapFault('InsufficientFunds', 'Insufficient funds for transfer.')

    @rpc(String, _returns=Account, soap_action='getAccountInfo')
    def getAccountInfo(self, account_number):
        account = self.accounts.get(account_number)
        if account:
            return account
        else:
            raise SoapFault('AccountNotFound', f'Account {account_number} not found.')

application = Application([FinancialService],
                          tns='spyne.examples.financial',
                          in_protocol=Soap11(),
                          out_protocol=Soap11())

